// Content hashing for the persistent face cache: text hashes key
// cached faces by their source and generated bytes; the tree hash is the
// compiler build's identity — a change ANYWHERE in the compiler tree
// (nested runtime/ fragments and grammar output included) must purge
// every cached face, since each one was produced by that build.
//
// Separate from the server so the hashing is unit-testable without
// spawning a live LSP session.

import fs from 'node:fs';
import path from 'node:path';

export const hashText = (text) => Bun.hash(text).toString(16);

// Recursive content hash over a directory tree's .js modules, keyed by
// tree-relative path so renames change the hash too. Directories named
// `test` and dot-directories are outside the build's identity;
// parser.js is generated, so grammar changes surface through it.
export function hashTree(dir) {
  const parts = [];
  const walk = (d, rel) => {
    let entries;
    try { entries = fs.readdirSync(d, { withFileTypes: true }); } catch { return; }
    entries.sort((a, b) => (a.name < b.name ? -1 : 1));
    for (const entry of entries) {
      if (entry.name.startsWith('.') || entry.name === 'node_modules' || entry.name === 'test') continue;
      if (entry.isDirectory()) {
        walk(path.join(d, entry.name), rel + entry.name + '/');
      } else if (entry.name.endsWith('.js')) {
        parts.push(rel + entry.name + ':' + Bun.hash(fs.readFileSync(path.join(d, entry.name))).toString(16));
      }
    }
  };
  walk(dir, '');
  return Bun.hash(parts.join(';')).toString(16);
}
